INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i05205ejlk9c3wgiepp1', 'cmp65v9c4009rlksaq15gbjva', 'Васильев Владислав', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-12 10:06:07.241'),
('cmp67i05d05fnlk9c2npbvz38', 'cmp66xht200b9lktg895k7lw5', 'Владимиров Николай', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-14 18:06:06.572'),
('cmp67i05m05gjlk9cxunm71lp', 'cmp5lt6zb0016gnb9wvpfrcg4', 'Соловьева Кюннэй Вадимовна', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '5', 'Для заочного формата — очень достойно: и структура, и проверка практики. Закрыл все модули, сертификатом доволен, буду использовать в резюме.', 't', '2026-04-12 01:14:21.436'),
('cmp67i05b05fdlk9ctl3v8yof', 'cmp65v9cn00aulksafyaupfrm', 'Попов Игорь', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '5', 'Сильная линейка модулей, всё связано с реальными ошибками пользователей. Прошёл до конца без «затыков». Сертификат — приятное подтверждение, что не зря вложился.', 't', '2026-04-06 11:12:43.557'),
('cmp67i05805f3lk9cgk766vo1', 'cmp65v9cj00ailksan4xe7qe0', 'Жирков Владислав', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-14 08:33:28.157'),
('cmp67i05805f5lk9ctl34rc9k', 'cmp65v9ck00allksagdzanvqk', 'Кочеваров Данил', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-12 07:37:21.887'),
('cmp67i05905f7lk9c8tyi1abr', 'cmp65v9cl00aolksadgqk0ca6', 'Лепеха Руслан', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-11 11:21:46.598'),
('cmp67i05905f9lk9csbn1l98g', 'cmp65v9cm00arlksaqf8xxbyo', 'Николаевич Игорь', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-14 14:17:29.564'),
('cmp67i05305ellk9cdk16trio', 'cmp65v9c6009ulksaqknlv6m0', 'Власов Максим', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-11 22:22:34.782'),
('cmp67i05h05fxlk9cu0cu9h7a', 'cmp5lt6z90013gnb9nyk14hhp', 'Слепцов Эрсан Арсентьевич', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-13 13:16:58.788'),
('cmp67i05305enlk9cb5rafoip', 'cmp65v9c8009xlksaxi9khj2y', 'Герасимов Сергей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-18 02:18:38.828'),
('cmp67i05g05ftlk9cnu6ec4od', 'cmp66xhta00bilktg9b770ns1', 'Окоемов Владимир', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-14 21:45:51.834'),
('cmp67i05g05fvlk9c313viz8a', 'cmp66xhtd00bllktgz26juqlv', 'Степанов Александр', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-13 04:20:55.269'),
('cmp67i05h05fzlk9c9jhyj6wt', 'cmp66xhtg00bolktgxcdq3ruq', 'Устинов Степан', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-12 12:59:01.692'),
('cmp67i05k05g9lk9c4m1qzt5d', 'cmp66xhzl00c3lktgqpfh6zhd', 'Максимова Мария', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-10 15:56:01.712'),
('cmp67i05i05g1lk9cz9xfc30x', 'cmp66xhz800brlktgy8ocaepw', 'Аторин Вячеслав', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-13 14:12:00.457'),
('cmp67i05i05g3lk9c4dtea2vu', 'cmp66xhzd00bulktg7b6xy698', 'Жаббаров Сергей', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-12 06:50:50.353'),
('cmp67i05j05g5lk9cz9yua4yi', 'cmp66xhzg00bxlktg8nmcsvcj', 'Колесников Семен', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '2', 'Дошёл до сертификата, но устал от объёма чтения. Польза есть, но эмоций мало — скорее «отработал норму».', 't', '2026-04-13 04:54:29.944'),
('cmp67i05j05g7lk9cbwn48h5t', 'cmp66xhzi00c0lktg64i5sdqv', 'Константинов Александр', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-13 13:34:40.981'),
('cmp67i05k05gblk9c7lb1ugyo', 'cmp66xhzn00c6lktg9aa1zajv', 'Певчих Сергей Григорьевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-23, 4 курс', '5', 'Отличный порядок тем: от паролей до разборов. Практика после лекций — то, что нужно. Курс завершил, сертификатом доволен, преподавателю показал без стыда.', 't', '2026-04-13 18:26:03.751'),
('cmp67i05l05gflk9cw0tbzco6', 'cmp66xi6700cclktg48p8nt0j', 'Бурцев Александр Михайлович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '5', 'Для заочного формата — очень достойно: и структура, и проверка практики. Закрыл все модули, сертификатом доволен, буду использовать в резюме.', 't', '2026-04-12 12:32:35.521'),
('cmp67i05l05gdlk9cpqu923ms', 'cmp66xi6000c9lktgneacod7y', 'Белимов Тимур Станиславович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-11 03:09:08.08'),
('cmp67i05m05ghlk9c8qrgb74p', 'cmp66xi6b00cflktgrwwrk69y', 'Иванов Андрей Иванович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '3', 'В целом ок: прошёл, получил сертификат. Иногда не хватало короткого резюме после длинной лекции. Для базы по ИБ — нормально.', 't', '2026-04-15 08:54:41.84'),
('cmp67i05o05gplk9c2ta8i6fu', 'cmp66xi6j00colktgo15onxv4', 'Киприянова Яна Ньургуновна', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-13 15:18:20.994'),
('cmp67i05o05grlk9cc2ueset3', 'cmp66xi6m00crlktgjxl7k32c', 'Кравец Айаал Гаврильевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-11 02:41:05.97');